+    /// Valid config with max port value round-trips.
+    #[test]
+    fn config_max_port_serde(_dummy in 0..1u8) {
+        let config = EmailNotifyConfig {
+            enabled: true,
+            smtp_host: "mail.example.com".to_string(),
+            smtp_port: u16::MAX,
+            tls: EmailTlsMode::Tls,
